import{_ as t,o as i,c as n,a2 as a}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse(`{"title":"Chapter 15: Extensibility Patterns","description":"Design plugin architectures, event systems, and extension points that let users and third parties extend your coding agent's capabilities.","frontmatter":{"title":"Chapter 15: Extensibility Patterns","description":"Design plugin architectures, event systems, and extension points that let users and third parties extend your coding agent's capabilities."},"headers":[],"relativePath":"learn/linear/15-extensibility-patterns/index.md","filePath":"learn/linear/15-extensibility-patterns/index.md"}`),r={name:"learn/linear/15-extensibility-patterns/index.md"};function s(l,e,o,h,c,d){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="extensibility-patterns" tabindex="-1">Extensibility Patterns <a class="header-anchor" href="#extensibility-patterns" aria-label="Permalink to &quot;Extensibility Patterns&quot;">​</a></h1><p>A coding agent that can only do what its original authors built is fundamentally limited. The most successful developer tools -- VS Code, Neovim, Emacs -- thrive because they are extensible platforms, not just fixed applications. This chapter teaches you how to design your coding agent as an extensible platform where new tools, providers, workflows, and integrations can be added without modifying the core codebase.</p><p>We begin with plugin architecture patterns and loading strategies, then build the foundational infrastructure: an event bus for decoupled communication and a hook system for intercepting and modifying agent behavior. A major focus is the Model Context Protocol (MCP), the emerging standard for connecting agents to external tool and resource servers. You will implement MCP client support for both tool servers and resource servers, giving your agent access to a growing ecosystem of capabilities.</p><p>The chapter also covers skill systems (higher-level abstractions over tools), configuration-driven extensions, hot reload for development workflows, and the critical security and versioning concerns that arise when running third-party code. By the end, you will understand how to build an agent that grows more capable over time through community contributions rather than just core development.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Design plugin architectures that support dynamic loading, lifecycle management, and clean isolation</li><li>Implement an event bus and hook system that lets extensions observe and modify agent behavior at key points</li><li>Build MCP client support for connecting to external tool servers and resource servers</li><li>Design a skill system that packages tools, prompts, and workflows into reusable higher-level capabilities</li><li>Implement hot reload for rapid plugin development without restarting the agent</li><li>Address security, isolation, and versioning challenges that arise with third-party extensions</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/15-extensibility-patterns/01-plugin-architecture-patterns.html">Plugin Architecture Patterns</a></li><li><a href="/linear/15-extensibility-patterns/02-loading-strategies.html">Loading Strategies</a></li><li><a href="/linear/15-extensibility-patterns/03-event-bus-design.html">Event Bus Design</a></li><li><a href="/linear/15-extensibility-patterns/04-hook-systems.html">Hook Systems</a></li><li><a href="/linear/15-extensibility-patterns/05-model-context-protocol.html">Model Context Protocol</a></li><li><a href="/linear/15-extensibility-patterns/06-mcp-tool-servers.html">MCP Tool Servers</a></li><li><a href="/linear/15-extensibility-patterns/07-mcp-resource-servers.html">MCP Resource Servers</a></li><li><a href="/linear/15-extensibility-patterns/08-skill-system-design.html">Skill System Design</a></li><li><a href="/linear/15-extensibility-patterns/09-configuration-driven-extensions.html">Configuration Driven Extensions</a></li><li><a href="/linear/15-extensibility-patterns/10-hot-reload-patterns.html">Hot Reload Patterns</a></li><li><a href="/linear/15-extensibility-patterns/11-isolation-and-security.html">Isolation and Security</a></li><li><a href="/linear/15-extensibility-patterns/12-versioning-plugins.html">Versioning Plugins</a></li><li><a href="/linear/15-extensibility-patterns/13-extension-testing.html">Extension Testing</a></li><li><a href="/linear/15-extensibility-patterns/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 5 (tool system architecture and registration patterns)</li><li>Chapter 14 (provider abstraction and trait-based design)</li></ul>',10)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
